```plantuml
@startuml
package controller {
  class File {
    - save()
    - load()
    - make_directory()
    - remove_directory()
    - is_file_path_ok()
  }
  class AnalyseData
  package conversation {
  }
  class AnalyseWeatherData
}

package models {
  class Forecaster {
    - name: string
    - my_name: string
    - speak_color: string
    + hello()
    + goodbye()
  }
  class CSVModel
  class MyForecaster {
    + ask_which_area()
    + ask_from_when_to_when()
    + say_results()
  }
  class JmaDataModel {
    + get_daily_weather_data()
    - get_http_body()
    - integrate_monthly_data()
    - str2float()
  }
  class File as ModelsFile
}

package views {
  class Console {
    + downloading_data()
    + get_template_dir_path()
    + find_template()
    + get_template()
  }
  class Graph
}

package template {
  file say_hello
  file say_goodbye
  file which_area_do_you_want
  file which_period_do_you_want
  file say_weather_data_analysis_results
}

Forecaster <|-- MyForecaster
CSVModel <|-- JmaDataModel
MyForecaster - JmaDataModel
AnalyseData <|-- AnalyseWeatherData
MyForecaster -- AnalyseWeatherData
MyForecaster -- ModelsFile
MyForecaster -- Console
Console -- template

@enduml
